# OEIS sequence: A321250

# Transfer matrix on the torus C_n X C_n
# State = ordered pair of adjacent, disjoint column patterns; a(n) = trace(T^n).
import numpy as np, scipy.sparse as sp
def A321250(n):
    if n < 3:
        return [1, 1, 2][n]
    full = (1 << n) - 1
    up   = lambda x: ((x << 1) | (x >> (n - 1))) & full   # vertical neighbor up (cyclic)
    down = lambda x: ((x >> 1) | (x << (n - 1))) & full   # vertical neighbor down (cyclic)
    columns  = [x for x in range(full + 1) if x & up(x) == 0]        # vertically-independent columns
    self_dom = {x: (up(x) | down(x)) & ~x & full for x in columns}   # rows a column dominates itself
    states   = [(a, b) for a in columns for b in columns if a & b == 0]
    index    = {s: i for i, s in enumerate(states)}
    src, dst = [], []
    for (left, mid) in states:
        need_right = full & ~mid & ~(self_dom[mid] | left)          # unchosen rows of mid still undominated
        for right in columns:
            if mid & right == 0 and need_right & ~right == 0:       # disjoint; right finishes domination
                src.append(index[(left, mid)]); dst.append(index[(mid, right)])
    N = len(states)
    T = sp.csr_matrix((np.ones(len(src), np.int64), (src, dst)), shape=(N, N))
    power, base, k = sp.identity(N, np.int64, format='csr'), T, n
    while k:
        if k & 1: power = power @ base
        k >>= 1
        if k: base = base @ base
    return int(power.diagonal().sum()) # a(n) = trace(T^n)
